1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Damage = { itemType: string; amount: number };
3	type Incident = { cause?: string; damages: Damage[] };
4	type QuoteStep = { op?: "quote"; items: Item[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Scenario = { customer?: { yearsWithMHPCO?: number }; steps: Step[] };
8	
9	const PROCESSING_FEE = 5;
10	const COMPONENT_BASE_PER_ITEM = 25;
11	const COMPONENT_BLOCK_OF_THREE_BASE = 60;
12	
13	const CURSED_SURCHARGE_RATE = 0.5;
14	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
15	const FIRST_INSURANCE_MARKUP_RATE = 0.1;
16	const LOYALTY_DISCOUNT_RATE = 0.2;
17	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
18	const LOYALTY_YEARS_THRESHOLD = 2;
19	const HIGH_ENCHANTMENT_THRESHOLD = 5;
20	
21	const CLAIM_DEDUCTIBLE = 100;
22	const CAP_MULTIPLIER = 2;
23	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
24	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
25	
26	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
27	  sword: 100,
28	  amulet: 60,
29	  staff: 80,
30	  potion: 40,
31	};
32	
33	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
34	  sword: 1000,
35	  amulet: 600,
36	  rune: 250,
37	};
38	
39	type PolicyState = { items: Item[]; remainingCap: number };
40	
41	export function runScenario(input: unknown): unknown {
42	  const { customer, steps } = input as Scenario;
43	  const years = customer?.yearsWithMHPCO ?? 0;
44	  const policies: Record<number, PolicyState> = {};
45	  const results = steps.map((step, index) => {
46	    if (step.op === "claim") return computeClaim(step, policies);
47	    const isFollowUp = index >= 1;
48	    policies[index] = { items: step.items, remainingCap: CAP_MULTIPLIER * insuranceSumFor(step.items) };
49	    return { premium: computePremium(step.items, years, isFollowUp) };
50	  });
51	  return { results };
52	}
53	
54	function insuranceSumFor(items: Item[]): number {
55	  return items.reduce((sum, item) => sum + INSURANCE_VALUE_BY_TYPE[item.type], 0);
56	}
57	
58	function computeClaim(step: ClaimStep, policies: Record<number, PolicyState>): { payout: number; remainingCap: number } {
59	  const policy = policies[step.policy];
60	  const payout = Math.floor(step.incident.damages.reduce((sum, damage) => sum + reimbursementFor(damage, policy.items), 0));
61	  policy.remainingCap -= payout;
62	  return { payout, remainingCap: policy.remainingCap };
63	}
64	
65	function reimbursementFor(damage: Damage, items: Item[]): number {
66	  const item = items.find((i) => i.type === damage.itemType);
67	  const rate = item !== undefined && isHighlyEnchantedForClaim(item) ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE : 1;
68	  return Math.max(0, damage.amount * rate - CLAIM_DEDUCTIBLE);
69	}
70	
71	function isHighlyEnchantedForClaim(item: Item): boolean {
72	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
73	}
74	
75	function computePremium(items: Item[], years: number, isFollowUp: boolean): number {
76	  if (items.length === 0) return PROCESSING_FEE;
77	  if (items.every(isComponent)) return componentsPremium(items);
78	  return mainItemsPremium(items, years, isFollowUp);
79	}
80	
81	function mainItemsPremium(items: Item[], years: number, isFollowUp: boolean): number {
82	  const policyBase = items.reduce((sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type], 0);
83	  const itemSubtotalSum = items.reduce((sum, item) => sum + itemSubtotal(item), 0);
84	  const policyMod = (cond: boolean, rate: number) => (cond ? policyBase * rate : 0);
85	  const loyaltyDiscount = policyMod(years >= LOYALTY_YEARS_THRESHOLD, LOYALTY_DISCOUNT_RATE);
86	  const followUpDiscount = policyMod(isFollowUp, FOLLOW_UP_DISCOUNT_RATE);
87	  return Math.ceil(itemSubtotalSum - loyaltyDiscount - followUpDiscount) + PROCESSING_FEE;
88	}
89	
90	function itemSubtotal(item: Item): number {
91	  const base = BASE_PREMIUM_BY_TYPE[item.type];
92	  const surchargeIf = (cond: boolean, rate: number) => (cond ? base * rate : 0);
93	  const cursedSurcharge = surchargeIf(item.cursed === true, CURSED_SURCHARGE_RATE);
94	  const highEnchSurcharge = surchargeIf(isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE_RATE);
95	  const firstInsuranceMarkup = base * FIRST_INSURANCE_MARKUP_RATE;
96	  return base + cursedSurcharge + highEnchSurcharge + firstInsuranceMarkup;
97	}
98	
99	function isHighlyEnchanted(item: Item): boolean {
100	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
101	}
102	
103	function componentsPremium(items: Item[]): number {
104	  const runes = items.filter((i) => i.type === "rune").length;
105	  const moonstones = items.filter((i) => i.type === "moonstone").length;
106	  return premiumFromBase(componentTypeBase(runes) + componentTypeBase(moonstones));
107	}
108	
109	function componentTypeBase(count: number): number {
110	  return count === 3 ? COMPONENT_BLOCK_OF_THREE_BASE : count * COMPONENT_BASE_PER_ITEM;
111	}
112	
113	function isComponent(item: Item): boolean {
114	  return item.type === "rune" || item.type === "moonstone";
115	}
116	
117	function premiumFromBase(base: number): number {
118	  return Math.ceil((base * 11) / 10) + PROCESSING_FEE;
119	}
